INSERT INTO upgrade_auto_responses (step_key, message_text, buttons, display_order, is_enabled, typing_enabled, typing_duration_seconds, trigger_type, trigger_value, language) VALUES
('language_hi', E'स्वागत है! 👋\n\nकृपया वह भाषा चुनें जिससे आप परिचित हैं:', '[{"key":"en","label":"🇬🇧 English","next_step":"confirm","is_enabled":true},{"key":"hi","label":"🇮🇳 हिन्दी (Hindi)","next_step":"confirm","is_enabled":true},{"key":"ml","label":"🇮🇳 മലയാളം (Malayalam)","next_step":"confirm","is_enabled":true},{"key":"ur","label":"🇵🇰 اردو (Urdu)","next_step":"confirm","is_enabled":true},{"key":"ar","label":"🇸🇦 العربية (Arabic)","next_step":"confirm","is_enabled":true}]'::jsonb, 0, true, true, 10, 'first_message', NULL, 'hi'),
('language_ml', E'സ്വാഗതം! 👋\n\nദയവായി നിങ്ങൾക്ക് പരിചയമുള്ള ഒരു ഭാഷ തിരഞ്ഞെടുക്കുക:', '[{"key":"en","label":"🇬🇧 English","next_step":"confirm","is_enabled":true},{"key":"hi","label":"🇮🇳 हिन्दी (Hindi)","next_step":"confirm","is_enabled":true},{"key":"ml","label":"🇮🇳 മലയാളം (Malayalam)","next_step":"confirm","is_enabled":true},{"key":"ur","label":"🇵🇰 اردو (Urdu)","next_step":"confirm","is_enabled":true},{"key":"ar","label":"🇸🇦 العربية (Arabic)","next_step":"confirm","is_enabled":true}]'::jsonb, 0, true, true, 10, 'first_message', NULL, 'ml'),
('language_ur', E'خوش آمدید! 👋\n\nبراہ کرم وہ زبان منتخب کریں جس سے آپ واقف ہیں:', '[{"key":"en","label":"🇬🇧 English","next_step":"confirm","is_enabled":true},{"key":"hi","label":"🇮🇳 हिन्दी (Hindi)","next_step":"confirm","is_enabled":true},{"key":"ml","label":"🇮🇳 മലയാളം (Malayalam)","next_step":"confirm","is_enabled":true},{"key":"ur","label":"🇵🇰 اردو (Urdu)","next_step":"confirm","is_enabled":true},{"key":"ar","label":"🇸🇦 العربية (Arabic)","next_step":"confirm","is_enabled":true}]'::jsonb, 0, true, true, 10, 'first_message', NULL, 'ur'),
('language_ar', E'مرحباً! 👋\n\nيرجى اختيار اللغة التي تعرفها:', '[{"key":"en","label":"🇬🇧 English","next_step":"confirm","is_enabled":true},{"key":"hi","label":"🇮🇳 हिन्दी (Hindi)","next_step":"confirm","is_enabled":true},{"key":"ml","label":"🇮🇳 മلయாളம் (Malayalam)","next_step":"confirm","is_enabled":true},{"key":"ur","label":"🇵🇰 اردو (Urdu)","next_step":"confirm","is_enabled":true},{"key":"ar","label":"🇸🇦 العربية (Arabic)","next_step":"confirm","is_enabled":true}]'::jsonb, 0, true, true, 10, 'first_message', NULL, 'ar'),
('confirm_en', 'Do you want to change the plan for your wallet?', '[{"key":"yes","label":"✅ Yes, I want to change wallet","next_step":"details","is_enabled":true},{"key":"no","label":"❌ No, I don''t want to switch wallets","next_step":"","is_enabled":true},{"key":"change_lang","label":"🌐 I want to change language","next_step":"language","is_enabled":true}]'::jsonb, 1, true, true, 10, 'button_click', 'language', 'en'),
('confirm_hi', E'क्या आप अपने वॉलेट का प्लान बदलना चाहते हैं?', '[{"key":"yes","label":"✅ हाँ, मैं वॉलेट बदलना चाहता/चाहती हूँ","next_step":"details","is_enabled":true},{"key":"no","label":"❌ नहीं, मैं वॉलेट नहीं बदलना चाहता/चाहती","next_step":"","is_enabled":true},{"key":"change_lang","label":"🌐 मैं भाषा बदलना चाहता/चाहती हूँ","next_step":"language","is_enabled":true}]'::jsonb, 1, true, true, 10, 'button_click', 'language', 'hi'),
('confirm_ml', E'നിങ്ങളുടെ വാലറ്റിന്റെ പ്ലാൻ മാറ്റാൻ ആഗ്രഹിക്കുന്നുണ്ടോ?', '[{"key":"yes","label":"✅ അതെ, ഞാൻ വാലറ്റ് മാറ്റാൻ ആഗ്രഹിക്കുന്നു","next_step":"details","is_enabled":true},{"key":"no","label":"❌ ഇല്ല, ഞാൻ വാലറ്റ് മാറ്റാൻ ആഗ്രഹിക്കുന്നില്ല","next_step":"","is_enabled":true},{"key":"change_lang","label":"🌐 ഭാഷ മാറ്റാൻ ഞാൻ ആഗ്രഹിക്കുന്നു","next_step":"language","is_enabled":true}]'::jsonb, 1, true, true, 10, 'button_click', 'language', 'ml'),
('confirm_ur', E'کیا آپ اپنے والٹ کا پلان تبدیل کرنا چاہتے ہیں؟', '[{"key":"yes","label":"✅ ہاں، میں والٹ تبدیل کرنا چاہتا ہوں","next_step":"details","is_enabled":true},{"key":"no","label":"❌ نہیں، میں والٹ تبدیل نہیں کرنا چاہتا","next_step":"","is_enabled":true},{"key":"change_lang","label":"🌐 میں زبان تبدیل کرنا چاہتا ہوں","next_step":"language","is_enabled":true}]'::jsonb, 1, true, true, 10, 'button_click', 'language', 'ur'),
('confirm_ar', E'هل تريد تغيير خطة محفظتك؟', '[{"key":"yes","label":"✅ نعم، أريد تغيير المحفظة","next_step":"details","is_enabled":true},{"key":"no","label":"❌ لا، لا أريد تبديل المحافظ","next_step":"","is_enabled":true},{"key":"change_lang","label":"🌐 أريد تغيير اللغة","next_step":"language","is_enabled":true}]'::jsonb, 1, true, true, 10, 'button_click', 'language', 'ar'),
('details_en', E'📋 *Wallet Upgrade Details*\n\n👤 Employee: {{employee_name}}\n💼 Current Wallet: {{current_wallet}}\n🎯 Selected Wallet: {{requested_wallet}}\n💰 Wallet Price: {{price}}\n\n✨ *Features:*\n{{features}}\n\n---\n\nDear {{employee_name}},\n\nTo upgrade your wallet plan, a payment is required.\nThe wallet plan you have selected is *{{requested_wallet}}*.\nThe price of this wallet plan is *{{price}}*.\nTherefore, the total amount you need to pay for the upgrade is *{{price}}*.\n\nKindly complete the payment to proceed with the upgrade.\nThank you for your cooperation. 🙏', '[]'::jsonb, 2, true, true, 10, 'button_click', 'confirm', 'en'),
('details_hi', E'📋 *वॉलेट अपग्रेड विवरण*\n\n👤 कर्मचारी: {{employee_name}}\n💼 वर्तमान वॉलेट: {{current_wallet}}\n🎯 चयनित वॉलेट: {{requested_wallet}}\n💰 वॉलेट मूल्य: {{price}}\n\n✨ *विशेषताएँ:*\n{{features}}\n\nकृपया अपग्रेड के लिए भुगतान पूरा करें। 🙏', '[]'::jsonb, 2, true, true, 10, 'button_click', 'confirm', 'hi'),
('details_ml', E'📋 *വാലറ്റ് അപ്‌ഗ്രേഡ് വിവരങ്ങൾ*\n\n👤 ജീവനക്കാരൻ: {{employee_name}}\n💼 നിലവിലെ വാലറ്റ്: {{current_wallet}}\n🎯 തിരഞ്ഞെടുത്ത വാലറ്റ്: {{requested_wallet}}\n💰 വാലറ്റ് വില: {{price}}\n\n✨ *ഫീച്ചറുകൾ:*\n{{features}}\n\nദയവായി പേയ്‌മെന്റ് പൂർത്തിയാക്കുക. 🙏', '[]'::jsonb, 2, true, true, 10, 'button_click', 'confirm', 'ml'),
('details_ur', E'📋 *والٹ اپ گریڈ تفصیلات*\n\n👤 ملازم: {{employee_name}}\n💼 موجودہ والٹ: {{current_wallet}}\n🎯 منتخب والٹ: {{requested_wallet}}\n💰 والٹ قیمت: {{price}}\n\n✨ *خصوصیات:*\n{{features}}\n\nبراہ کرم ادائیگی مکمل کریں۔ 🙏', '[]'::jsonb, 2, true, true, 10, 'button_click', 'confirm', 'ur'),
('details_ar', E'📋 *تفاصيل ترقية المحفظة*\n\n👤 الموظف: {{employee_name}}\n💼 المحفظة الحالية: {{current_wallet}}\n🎯 المحفظة المختارة: {{requested_wallet}}\n💰 السعر: {{price}}\n\n✨ *الميزات:*\n{{features}}\n\nيرجى إتمام الدفع. 🙏', '[]'::jsonb, 2, true, true, 10, 'button_click', 'confirm', 'ar'),
('payment_en', '', '[{"key":"pay","label":"💳 Pay ({{price}})","next_step":"waiting","is_enabled":true},{"key":"cancel","label":"❌ Cancel Pay ({{price}})","next_step":"","is_enabled":true}]'::jsonb, 3, true, true, 10, 'button_click', 'details', 'en'),
('payment_hi', '', '[{"key":"pay","label":"💳 भुगतान करें ({{price}})","next_step":"waiting","is_enabled":true},{"key":"cancel","label":"❌ भुगतान रद्द करें ({{price}})","next_step":"","is_enabled":true}]'::jsonb, 3, true, true, 10, 'button_click', 'details', 'hi'),
('payment_ml', '', '[{"key":"pay","label":"💳 പേയ് ചെയ്യുക ({{price}})","next_step":"waiting","is_enabled":true},{"key":"cancel","label":"❌ പേയ് റദ്ദാക്കുക ({{price}})","next_step":"","is_enabled":true}]'::jsonb, 3, true, true, 10, 'button_click', 'details', 'ml'),
('payment_ur', '', '[{"key":"pay","label":"💳 ادائیگی کریں ({{price}})","next_step":"waiting","is_enabled":true},{"key":"cancel","label":"❌ ادائیگی منسوخ کریں ({{price}})","next_step":"","is_enabled":true}]'::jsonb, 3, true, true, 10, 'button_click', 'details', 'ur'),
('payment_ar', '', '[{"key":"pay","label":"💳 ادفع ({{price}})","next_step":"waiting","is_enabled":true},{"key":"cancel","label":"❌ إلغاء ({{price}})","next_step":"","is_enabled":true}]'::jsonb, 3, true, true, 10, 'button_click', 'details', 'ar'),
('offline_message_en', E'⏳ All our agents are currently busy assisting other customers.\n\nKindly try again after some time.\nWe appreciate your understanding. 🙏', '[]'::jsonb, 4, true, true, 10, 'button_click', 'payment', 'en'),
('offline_message_hi', E'⏳ हमारे सभी एजेंट वर्तमान में व्यस्त हैं।\n\nकृपया कुछ समय बाद पुनः प्रयास करें। 🙏', '[]'::jsonb, 4, true, true, 10, 'button_click', 'payment', 'hi'),
('offline_message_ml', E'⏳ ഞങ്ങളുടെ എല്ലാ ഏജന്റുമാരും ഇപ്പോൾ തിരക്കിലാണ്.\n\nദയവായി കുറച്ച് സമയത്തിന് ശേഷം ശ്രമിക്കുക. 🙏', '[]'::jsonb, 4, true, true, 10, 'button_click', 'payment', 'ml'),
('offline_message_ur', E'⏳ ہمارے تمام ایجنٹ مصروف ہیں۔\n\nبراہ کرم بعد میں کوشش کریں۔ 🙏', '[]'::jsonb, 4, true, true, 10, 'button_click', 'payment', 'ur'),
('offline_message_ar', E'⏳ جميع وكلائنا مشغولون حالياً.\n\nيرجى المحاولة لاحقاً. 🙏', '[]'::jsonb, 4, true, true, 10, 'button_click', 'payment', 'ar'),
('appointment_intro_en', E'📅 Would you like to book an appointment with our team?\n\nPlease select a preferred day below:', '[]'::jsonb, 5, true, true, 10, 'button_click', 'offline_message', 'en'),
('appointment_intro_hi', E'📅 क्या आप हमारी टीम के साथ अपॉइंटमेंट बुक करना चाहेंगे?\n\nकृपया नीचे एक दिन चुनें:', '[]'::jsonb, 5, true, true, 10, 'button_click', 'offline_message', 'hi'),
('appointment_intro_ml', E'📅 ഞങ്ങളുടെ ടീമുമായി ഒരു അപ്പോയിന്റ്‌മെന്റ് ബുക്ക് ചെയ്യാൻ ആഗ്രഹിക്കുന്നുണ്ടോ?', '[]'::jsonb, 5, true, true, 10, 'button_click', 'offline_message', 'ml'),
('appointment_intro_ur', E'📅 کیا آپ ہماری ٹیم کے ساتھ ملاقات بک کرنا چاہیں گے؟', '[]'::jsonb, 5, true, true, 10, 'button_click', 'offline_message', 'ur'),
('appointment_intro_ar', E'📅 هل تود حجز موعد مع فريقنا؟', '[]'::jsonb, 5, true, true, 10, 'button_click', 'offline_message', 'ar'),
('select_time_en', 'Please select a preferred time slot:', '[]'::jsonb, 6, true, true, 10, 'button_click', 'appointment_intro', 'en'),
('select_time_hi', E'कृपया एक समय स्लॉट चुनें:', '[]'::jsonb, 6, true, true, 10, 'button_click', 'appointment_intro', 'hi'),
('select_time_ml', E'ദയവായി ഒരു സമയ സ്ലോട്ട് തിരഞ്ഞെടുക്കുക:', '[]'::jsonb, 6, true, true, 10, 'button_click', 'appointment_intro', 'ml'),
('select_time_ur', E'براہ کرم ایک وقت منتخب کریں:', '[]'::jsonb, 6, true, true, 10, 'button_click', 'appointment_intro', 'ur'),
('select_time_ar', E'يرجى اختيار وقت:', '[]'::jsonb, 6, true, true, 10, 'button_click', 'appointment_intro', 'ar'),
('booking_confirmed_en', E'✅ Your appointment has been booked successfully.\n\n📋 Booking Details:\n📅 Day: {{day}}\n📆 Date: {{date}}\n🕐 Time: {{time}}\n\nPlease be available at the scheduled time.\nThank you for your cooperation. 🙏', '[]'::jsonb, 7, true, true, 10, 'button_click', 'select_time', 'en'),
('booking_confirmed_hi', E'✅ आपका अपॉइंटमेंट सफलतापूर्वक बुक हो गया।\n\n📋 बुकिंग विवरण:\n📅 दिन: {{day}}\n📆 तारीख: {{date}}\n🕐 समय: {{time}}\n\nकृपया निर्धारित समय पर उपलब्ध रहें। 🙏', '[]'::jsonb, 7, true, true, 10, 'button_click', 'select_time', 'hi'),
('booking_confirmed_ml', E'✅ നിങ്ങളുടെ അപ്പോയിന്റ്‌മെന്റ് ബുക്ക് ചെയ്തു.\n\n📅 ദിവസം: {{day}}\n📆 തീയതി: {{date}}\n🕐 സമയം: {{time}}\n\nനിർദ്ദിഷ്ട സമയത്ത് ലഭ്യമായിരിക്കുക. 🙏', '[]'::jsonb, 7, true, true, 10, 'button_click', 'select_time', 'ml'),
('booking_confirmed_ur', E'✅ آپ کی ملاقات بک ہو گئی۔\n\n📅 دن: {{day}}\n📆 تاریخ: {{date}}\n🕐 وقت: {{time}}\n\nمقررہ وقت پر دستیاب رہیں۔ 🙏', '[]'::jsonb, 7, true, true, 10, 'button_click', 'select_time', 'ur'),
('booking_confirmed_ar', E'✅ تم حجز موعدك بنجاح.\n\n📅 اليوم: {{day}}\n📆 التاريخ: {{date}}\n🕐 الوقت: {{time}}\n\nيرجى التواجد في الوقت المحدد. 🙏', '[]'::jsonb, 7, true, true, 10, 'button_click', 'select_time', 'ar'),
('booking_cancelled_en', E'❌ Your booking process has been cancelled successfully.', '[]'::jsonb, 8, true, true, 10, 'button_click', NULL, 'en'),
('booking_cancelled_hi', E'❌ आपकी बुकिंग प्रक्रिया रद्द कर दी गई।', '[]'::jsonb, 8, true, true, 10, 'button_click', NULL, 'hi'),
('booking_cancelled_ml', E'❌ നിങ്ങളുടെ ബുക്കിംഗ് റദ്ദാക്കി.', '[]'::jsonb, 8, true, true, 10, 'button_click', NULL, 'ml'),
('booking_cancelled_ur', E'❌ آپ کی بکنگ منسوخ ہو گئی۔', '[]'::jsonb, 8, true, true, 10, 'button_click', NULL, 'ur'),
('booking_cancelled_ar', E'❌ تم إلغاء عملية الحجز.', '[]'::jsonb, 8, true, true, 10, 'button_click', NULL, 'ar'),
('appointment_reminder_en', E'🔔 You have successfully booked an appointment.\nYour appointment time has started.\n\nTo keep your appointment active, please send a message such as ''Hi'' or ''Hello'' within the next 5 minutes.\n\nIf no message is received within 5 minutes, your appointment will be automatically cancelled.', '[]'::jsonb, 9, true, true, 10, 'time_based', NULL, 'en'),
('appointment_reminder_hi', E'🔔 आपका अपॉइंटमेंट शुरू हो गया है।\n\nकृपया 5 मिनट के भीतर ''Hi'' या ''Hello'' भेजें।', '[]'::jsonb, 9, true, true, 10, 'time_based', NULL, 'hi'),
('appointment_reminder_ml', E'🔔 നിങ്ങളുടെ അപ്പോയിന്റ്‌മെന്റ് സമയം ആരംഭിച്ചു.\n\n5 മിനിറ്റിനുള്ളിൽ ''Hi'' അയക്കുക.', '[]'::jsonb, 9, true, true, 10, 'time_based', NULL, 'ml'),
('appointment_reminder_ur', E'🔔 آپ کی ملاقات کا وقت شروع ہو گیا۔\n\n5 منٹ میں ''Hi'' بھیجیں۔', '[]'::jsonb, 9, true, true, 10, 'time_based', NULL, 'ur'),
('appointment_reminder_ar', E'🔔 بدأ وقت موعدك.\n\nأرسل ''Hi'' خلال 5 دقائق.', '[]'::jsonb, 9, true, true, 10, 'time_based', NULL, 'ar'),
('appointment_auto_cancel_en', E'⏰ Your appointment has been automatically cancelled due to no response.\n\nYou may book a new appointment at any time.', '[]'::jsonb, 10, true, true, 10, 'time_based', NULL, 'en'),
('appointment_auto_cancel_hi', E'⏰ कोई प्रतिक्रिया न मिलने के कारण अपॉइंटमेंट रद्द हो गया।', '[]'::jsonb, 10, true, true, 10, 'time_based', NULL, 'hi'),
('appointment_auto_cancel_ml', E'⏰ പ്രതികരണമില്ലാത്തതിനാൽ അപ്പോയിന്റ്‌മെന്റ് റദ്ദാക്കി.', '[]'::jsonb, 10, true, true, 10, 'time_based', NULL, 'ml'),
('appointment_auto_cancel_ur', E'⏰ جواب نہ ملنے کی وجہ سے ملاقات منسوخ ہو گئی۔', '[]'::jsonb, 10, true, true, 10, 'time_based', NULL, 'ur'),
('appointment_auto_cancel_ar', E'⏰ تم إلغاء الموعد تلقائياً لعدم الاستجابة.', '[]'::jsonb, 10, true, true, 10, 'time_based', NULL, 'ar'),
('appointment_confirmed_en', E'✅ Your appointment has been confirmed successfully.\nPlease stay available for your scheduled session.', '[]'::jsonb, 11, true, true, 10, 'keyword', NULL, 'en'),
('appointment_confirmed_hi', E'✅ आपका अपॉइंटमेंट सफलतापूर्वक पुष्टि हो गया।', '[]'::jsonb, 11, true, true, 10, 'keyword', NULL, 'hi'),
('appointment_confirmed_ml', E'✅ നിങ്ങളുടെ അപ്പോയിന്റ്‌മെന്റ് സ്ഥിരീകരിച്ചു.', '[]'::jsonb, 11, true, true, 10, 'keyword', NULL, 'ml'),
('appointment_confirmed_ur', E'✅ آپ کی ملاقات کی تصدیق ہو گئی۔', '[]'::jsonb, 11, true, true, 10, 'keyword', NULL, 'ur'),
('appointment_confirmed_ar', E'✅ تم تأكيد موعدك بنجاح.', '[]'::jsonb, 11, true, true, 10, 'keyword', NULL, 'ar')
